const msg = $input.first().json;
const chatId = msg.message?.chat?.id || msg.callback_query?.message?.chat?.id;
const text = msg.message?.text || msg.callback_query?.data || '';
const firstName = msg.message?.from?.first_name || 'Paciente';
const userId = msg.message?.from?.id || '';
const isStart = text.startsWith('/start');

return [{
  json: { chatId, text, firstName, userId, isStart, timestamp: new Date().toISOString() }
}];

// ─── CONFIGURA ESTE VALOR POR CLIENTE ───────────────────────────────────────
const CLIENTE_ID = 1;  // ID del cliente en la tabla `clientes` de la DB
// ─────────────────────────────────────────────────────────────────────────────

const d = $input.first().json;
const canalId = String(d.userId || d.chatId || '').replace(/[^0-9a-zA-Z_-]/g, '');

// Escapar comillas simples para SQL (protección básica contra inyección)
const esc = (s) => String(s || '').replace(/'/g, "''").substring(0, 1000);

return [{
  json: {
    ...d,
    clienteId: CLIENTE_ID,
    canalId,
    textEsc: esc(d.text),
    nameEsc: esc(d.firstName)
  }
}];

const aiResponse = $('Claude IA — Agente').item.json.content[0].text || '';
const userText = $('Preparar Config DB').item.json.text || '';
const bookingKeywords = ['cita', 'reservar', 'agendar', 'disponibilidad', 'cuándo puedo', 'quiero pedir'];
const hasBookingIntent = bookingKeywords.some(kw =>
  userText.toLowerCase().includes(kw) || aiResponse.toLowerCase().includes(kw)
);
return [{ json: { ...($input.first().json), hasBookingIntent, chatId: $('Preparar Config DB').item.json.chatId } }];
